import { NextResponse } from "next/server";
import fs from "fs";
import path from "path";

const filePath = path.join(process.cwd(), "data", "database.json");

const readDatabaseFile = () => {
  if (!fs.existsSync(filePath)) return [];
  try {
    return JSON.parse(fs.readFileSync(filePath, "utf-8"));
  } catch (error) {
    return [];
  }
};

const writeDatabaseFile = (data: any) => {
  fs.writeFileSync(filePath, JSON.stringify(data, null, 2), "utf-8");
};

// ==========================================
// 🟡 1. THE PUT HANDLER (UPDATES CAR DETAILS)
// ==========================================
export async function PUT(request: Request, context: { params: any }) {
  try {
    const params = await context.params;
    const targetJobId = params.id;
    const body = await request.json();

    const currentDatabase = readDatabaseFile();
    const targetIndex = currentDatabase.findIndex((job: any) => job.id === targetJobId);

    if (targetIndex === -1) {
      return NextResponse.json({ error: "Job card index not found." }, { status: 404 });
    }

    const existingRecord = currentDatabase[targetIndex];

    // 🕒 AUTOMATIC TIMESTAMPS CONTROLLER
    let completedAtTimestamp = existingRecord.completedAt || null;
    
    if (body.status === "Completed" && existingRecord.status !== "Completed") {
      completedAtTimestamp = new Date().toISOString();
    } else if (body.status && body.status !== "Completed") {
      completedAtTimestamp = null;
    }

    currentDatabase[targetIndex] = {
      ...existingRecord,
      ...body,
      vehicleNumber: body.vehicleNumber ? body.vehicleNumber.trim().toUpperCase() : existingRecord.vehicleNumber,
      completedAt: completedAtTimestamp,
      updatedAt: new Date().toISOString()
    };

    writeDatabaseFile(currentDatabase);
    return NextResponse.json({ success: true, data: currentDatabase[targetIndex] });
  } catch (error) {
    return NextResponse.json({ error: "Internal Server Error processing updates." }, { status: 500 });
  }
}

// ==========================================
// 🔴 2. THE DELETE HANDLER (REMOVES THE CAR)
// ==========================================
export async function DELETE(request: Request, context: { params: any }) {
  try {
    const params = await context.params;
    const targetJobId = params.id;

    const currentDatabase = readDatabaseFile();
    const targetIndex = currentDatabase.findIndex((job: any) => job.id === targetJobId);

    if (targetIndex === -1) {
      return NextResponse.json({ error: "Job card index not found." }, { status: 404 });
    }

    // Remove the job card record from your database array
    currentDatabase.splice(targetIndex, 1);
    writeDatabaseFile(currentDatabase);

    return NextResponse.json({ success: true, message: "Job card purged successfully." });
  } catch (error) {
    return NextResponse.json({ error: "Internal Server Error deleting job asset." }, { status: 500 });
  }
}